<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>
        <div>
            <div class="row">
                <div class="col-md-12 padding-t_8">
                    <div class="theme-primary partition-full">
                        <span class="p-name text-white">{{ $t('Quotes') }}</span>
                    </div>
                </div>
            </div>
        </div>
        <div class="border p-3">
            <Form ref="form">
                <dynamic-form lang="en" ref="AddQuotes" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="OnSubmit"
                    :mandatorytext="MandatoryString">
                    <template v-slot:tgslot-QuotationNumber="{ data }">
                        <div class="input-group">
                            <input class="form-control devicefixermin768" tabindex="2" readonly="readonly"
