                                </span>
                            </div>
                        </div>
                    </template>
                    <template v-slot:tgslot-TemplateId="{ data }">

                        <Field name="TemplateId" :rules="{ required: true }" class="w-100 input-group">
                            <select v-model="SetTemplateId" name="TemplateId" class="form-control">
                                <option disabled value="">{{ $t('Select') }}</option>
                                <option v-for="item in TemplateData" :key="item.TEMPLATE_ID" :value="item.TEMPLATE_ID">
