                                    </a>
                                </span>
                            </div>
                        </Field>

                        <span class="examplenote_nd"></span>


                    </template>
                    <template v-slot:tgslot-BillingItems="{ data }">
                        <div class="heading-border">
                            <h5 class="h5">
                                <span>
                                    {{ $t('Billing Items') }}<small style="font-size:14px;"><i>({{
                                        $t('CostandProfitwillnotbevisibletoclient') }})</i></small>
