                                        <i class="fa fa-plus pr-1"></i>{{ $t('AddNewLine') }}
                                    </a>
                                </small>
                            </h5>
                        </div>
                        <div class="listing mt-2">
                            <div class="table-responsive table-fix-header">
                                <table class="table table-bordered dt-responsive nowrap mt-0" id="tblBillDetails">
                                    <thead class="thead-bg">
                                        <tr>
                                            <th style="min-width:200px;"><span class="d-inline">{{ $t('ItemName')
                                            }}</span><span class="text-danger d-inline">*</span></th>
                                            <th v-if="UserType != 'CL'" class="text-right" style="min-width:150px;">
                                                <span>{{ $t('Cost') }} {{ '(' + Currency + ')' }}</span>
                                            </th>
                                            <th class="text-right" style="min-width:150px;"><span
                                                    class="d-inline">{{ $t('Billing') }} {{ $t('Amount') }} {{ '('
                                                        + Currency + ')' }}</span><span class="text-danger d-inline">*</span>
                                            </th>
                                            <th class="text-right" style="min-width:190px;"><span class="d-inline">{{
                                                $t('Quantity') }}</span><span class="text-danger d-inline">*</span>
                                            </th>
                                            <th v-if="UserType != 'CL'" class="text-right" style="min-width:200px;">
                                                <span>{{ $t('Amount') }} {{ '(' + Currency + ')' }}</span>
                                            </th>
                                            <th v-if="UserType != 'CL'" class="text-right" style="min-width:200px;">
                                                <span>{{ $t('Profit') }}/{{ $t('Loss') }} {{ '(' + Currency + ')' }}</span>
                                            </th>
                                            <th class="text-center"><span>{{ $t('Actions') }}</span></th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr v-for="(item, index) in BillingItems" :key="index">
                                            <td>
                                                <input class="form-control" type="text" placeholder="Enter Product Name"
                                                    v-model="BillingItems[index].item"
                                                    v-bind:name="BillingItems[index].item" />
                                            </td>
                                            <td v-if="UserType != 'CL'">
                                                <input @keypress="validateNumericKey($event)"
                                                    @blur="CalculatePricePerRow(item, index, 'Bill')"
                                                    v-model="BillingItems[index].costing" class="form-control"
                                                    type="text" placeholder="Enter Cost"
                                                    v-bind:name="BillingItems[index].costing" />
                                            </td>
                                            <td>
                                                <input @keypress="validateNumericKey($event)"
                                                    @blur="CalculatePricePerRow(item, index, 'Bill')"
                                                    v-model="BillingItems[index].billing" class="form-control"
                                                    type="text" placeholder="Enter Billing"
                                                    v-bind:name="BillingItems[index].billing" />
                                            </td>
                                            <td class="qttion">
                                                <div class="row">
                                                    <div
                                                        class="col-2 col-sm-2 col-md-2 col-lg-2 col-xl-2 float-left align-middle text-center my-2 font-weight-bold">
                                                        x</div>
                                                    <div
                                                        class="col-10 col-sm-10 col-md-10 col-lg-10 col-xl-10 float-left">
                                                        <input class="form-control"
                                                            @keypress="validateNumericKey($event)"
                                                            @blur="CalculatePricePerRow(item, index, 'Bill')" type="text"
                                                            placeholder="Enter Quantity"
                                                            v-model="BillingItems[index].quantity"
                                                            v-bind:name="BillingItems[index].quantity" />
                                                    </div>
                                                </div>
                                            </td>
                                            <td>
                                                <input class="form-control disabled textfield" type="text"
                                                    placeholder="0.00" v-model="BillingItems[index].billedAmount"
                                                    v-bind:name="BillingItems[index].billedAmount" />
                                            </td>
                                            <td v-if="UserType != 'CL'">
                                                <input class="form-control disabled textfield" type="text"
                                                    placeholder="0.00" v-model="BillingItems[index].profit"
                                                    v-bind:name="BillingItems[index].profit" />
                                            </td>
                                            <td v-if="UserType != 'CL'">
                                                <a @click="DeleteRow('Billing', item, index)" class="BI single-action"
                                                    :class="{ 'disabled': index == 0 }">
                                                    <em class="fa fa-trash-o action-icon text-danger"
                                                        :class="{ 'disabled': index == 0 }"></em>
                                                </a>
                                            </td>
                                        </tr>
                                    </tbody>
                                    <tfoot>
                                        <tr>
                                            <td></td>
                                            <td v-if="UserType != 'CL'"></td>
                                            <td v-if="UserType != 'CL'"></td>
                                            <td></td>
                                            <td class="td4 arialb000000"><strong>{{ $t('SubTotal') }} {{ '(' + Currency
                                                + ')' }}:</strong></td>
                                            <td>
                                                <input type="text" id="txtTotalAmount" placeholder="0.00"
                                                    class="textfield form-control" v-model='TotalLinePrice' />
                                            </td>
                                            <td></td>
                                        </tr>
                                        <tr v-if="UserType != 'CL'">
                                            <td></td>
                                            <td></td>
                                            <td></td>
                                            <td></td>
                                            <td class="td4 arialb000000"><strong>{{ $t('Profit') }}/{{ $t('Loss') }} {{ '('
                                                + Currency + ')' }}:</strong></td>
                                            <td>
                                                <input type="text" id="txtTotalProfit" placeholder="0.00"
                                                    class="textfield form-control" v-model="TotalProfitAmount" />
                                            </td>
                                            <td></td>
                                        </tr>
                                    </tfoot>
                                </table>
                            </div>
                            <div class="row">
                                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 p-0 mt-2">
                                    <div class="col-sm-12 col-md-12 col-lg-12 col-xl-6 float-right">
                                        <div class="table-responsive table-fix-header">
                                            <table class="table table-bordered dt-responsive nowrap mt-0"
                                                id="tblDiscounts">
                                                <thead class="thead-bg">
                                                    <tr>
                                                        <th><span>{{ $t('Discount') }}:</span></th>
                                                        <th colspan="2">
                                                            <div class="form-check form-check-inline"
                                                                style="width:120px;">
                                                                <label class="form-check-label font-weight-normal mr-1"
                                                                    for="issequential">Is Stacked:</label>
                                                                <div
                                                                    class="custom-control custom-radio custom-control-inline">
                                                                    <input checked="checked" id="rdo_0"
                                                                        name="DiscountType" type="radio" value="0"
                                                                        class="custom-control-input">
                                                                    <label class="custom-control-label"
                                                                        for="rdo_0"></label>
                                                                </div>
                                                            </div>
                                                        </th>
                                                        <th colspan="2">
                                                            <div class="form-check form-check-inline"
                                                                style="width:135px;">
                                                                <label class="form-check-label font-weight-normal mr-1"
                                                                    for="stacked">Is Sequential:</label>
                                                                <div
                                                                    class="custom-control custom-radio custom-control-inline">
                                                                    <input id="rdo_1" name="DiscountType" type="radio"
                                                                        value="1" class="custom-control-input">
                                                                    <label class="custom-control-label"
                                                                        for="rdo_1"></label>
                                                                </div>
                                                            </div>
                                                        </th>
                                                        <th class="text-center" style="width:100px;"   @click="AddDisOrTaxRow($event)"
                                                            id="ancAddDiscount">
                                                            <a id="ancAddDiscount"
                                                                class="btn btn-primary float-right text-white"
                                                                title="Add Discount" data-placement="left"
                                                                @click="AddDisOrTaxRow($event)">
                                                                <i class="fa fa-plus pr-2"></i>{{ $t('Add') }}
                                                            </a>
                                                        </th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    <tr v-for="(item, index) in Adjustments" :key="index">
                                                        <template
                                                            v-if="item.adjOperator == '0' && item.adjType == 'Discounts'">
                                                            <td colspan="2" class="td1" style="min-width: 150px;">
                                                                <input class="textfield form-control" maxlength="100"
                                                                    type="text" v-model="item.adjName"
                                                                    v-bind:name="item.adjName" />
                                                            </td>
                                                            <td class="td2 tdcm text-right" style="min-width: 150px;">
                                                                <input class="textfield form-control" maxlength="5"
                                                                    type="text" v-model="item.adjPercentage"
                                                                    @blur="DiscountChange(item, index)"
                                                                    v-bind:name="item.adjPercentage" />
                                                            </td>
                                                            <td class="pl-0 text-center"><span
                                                                    class="float-left my-1">%</span></td>
                                                            <td class="td3 text-right" style="min-width: 150px;">
                                                                <input class="textfield form-control" maxlength="5"
                                                                    type="text" v-model="item.adjAmount"
                                                                    v-bind:name="item.adjAmount" readonly />
                                                            </td>
                                                            <td class="td4 text-center single-action"
                                                                v-if="UserType != 'CL'">
                                                                <a @click="DeleteRow('Discounts', item, index)"
                                                                    class="DIS">
                                                                    <em
                                                                        class="fa fa-trash-o action-icon text-danger"></em>
                                                                </a>
                                                            </td>
                                                        </template>
                                                    </tr>
                                                </tbody>
                                            </table>
                                        </div>
                                        <div class="table-responsive mt-2 table-fix-header">
                                            <table class="table table-bordered dt-responsive nowrap mt-0" id="tblTaxes">
                                                <thead class="thead-bg">
                                                    <tr>
                                                        <th colspan="5"><span>{{ $t('Taxes') }}:</span></th>
                                                        <th class="text-center" style="width:100px;" @click="AddDisOrTaxRow($event)">
                                                            <a id="ancAddTax"
                                                                class="btn btn-primary float-right text-white"
                                                                title="Add Taxes" data-placement="left">
                                                                <em class="fa fa-plus pr-2"></em>{{ $t('Add') }}
                                                            </a>
                                                        </th>
                                                    </tr>
                                                </thead>
                                                <tbody>
                                                    <tr v-for="(item, index) in Adjustments" :key="index">
                                                        <template v-if="item.adjOperator == '1' && item.adjType == 'Tax'">
                                                            <td colspan="2" class="td1" style="min-width: 150px;">
                                                                <input class="textfield form-control" maxlength="100"
                                                                    type="text" v-model="item.adjName"
                                                                    v-bind:name="item.adjName" />
                                                            </td>
                                                            <td class="td2 tdcm text-right" style="min-width: 150px;">
                                                                <input class="textfield form-control" maxlength="5"
                                                                    type="text" @blur="TaxChange(item, index)"
                                                                    v-model="item.adjPercentage"
                                                                    v-bind:name="item.adjPercentage" />
                                                            </td>
                                                            <td class="pl-0 text-center"><span
                                                                    class="float-left my-1">%</span></td>
                                                            <td class="td3 text-right" style="min-width: 150px;">
                                                                <input class="textfield form-control" maxlength="5"
                                                                    type="text" v-model="item.adjAmount"
                                                                    v-bind:name="item.adjAmount" readonly />
                                                            </td>
                                                            <td class="td4 text-center single-action"
                                                                v-if="UserType != 'CL'">
                                                                <a @click="DeleteRow('Tax', item, index)" class="TAX">
                                                                    <em
                                                                        class="fa fa-trash-o action-icon text-danger"></em>
                                                                </a>
                                                            </td>
                                                        </template>
                                                    </tr>
                                                </tbody>
                                            </table>
                                        </div>
                                        <div class="table-responsive mt-2">
                                            <table class="table table-bordered dt-responsive nowrap mt-0" id="">
                                                <thead class="thead-bg">
                                                </thead>
                                                <tbody>
                                                    <tr>
                                                        <td colspan="5" class="font-weight-bold text-right">{{
                                                            $t('Total') }} {{ '(' + Currency + ')' }}:</td>
                                                        <td></td>
                                                        <td style="min-width:150px;">
                                                            <input class="textfield form-control" type="text"
                                                                v-model="AmountAfterDiscount" name="AmountAfterDiscount"
                                                                readonly />
                                                        </td>
                                                        <td class="text-center"></td>
                                                    </tr>
                                                    <tr>
                                                        <td colspan="5" class="font-weight-bold text-right"
                                                            style="min-width:150px;">{{ $t('DiscountFlatRate')
                                                            }} {{ '('
                                                                + Currency + ')' }}:</td>
                                                        <td></td>
                                                        <td style="min-width:150px;">
                                                            <input class="textfield form-control" type="text"
                                                                v-model="FlatDiscount" name="FlatDiscount" />
                                                        </td>
                                                        <td class="text-center"></td>
                                                    </tr>
                                                    <tr>
                                                        <td colspan="5" class="font-weight-bold text-right"
                                                            style="min-width:150px;">{{ $t('AdvancedRecived') }}
                                                            {{ '('
                                                                + Currency + ')' }}:</td>
                                                        <td></td>
                                                        <td style="min-width:150px;">
                                                            <input class="textfield form-control" type="text"
                                                                v-model="AdvanceRecieved" name="AdvanceRecieved" />
                                                        </td>
                                                        <td class="text-center"></td>

                                                    </tr>
                                                    <tr>
                                                        <td colspan="5" class="font-weight-bold text-right">{{
                                                            $t('NetTotal') }} {{ '(' + Currency + ')' }}:</td>
                                                        <td></td>
                                                        <td style="min-width:150px;">
                                                            <input class="textfield form-control" type="text"
                                                                v-model="NetPayableAmount" name="NetPayableAmount"
                                                                readonly />
                                                        </td>
                                                        <td class="text-center"></td>
                                                    </tr>
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </template>
                </dynamic-form>
            </Form>
        </div>
        <PreViewTemplate v-if="IsPreviewTemplate" :Content="content"></PreViewTemplate>
    </section>
</template>
<script>
import DataService from '../../../services/DataService';
import PreViewTemplate from '../../../components/Modal/PreviewTemplate.vue'
export default {
    components: { PreViewTemplate },
    data() {
        return {
            userId: null,
            companyId: null,
            UserType: null,
            Currency: null,
            ProjectId: 0,
            IsGenerateNumber: '',
            SetTemplateId: 0,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            isLoading: false,
            FormSchema: [
                {
                    layoutType: "four",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Title'),
                            name: "QuotationTitle",
                            value: "",
                            placeholder: this.$t('Enter Title Name'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('QuotationNumber'),
                            name: "QuotationNumber",
                            value: "",
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "TextField",
                            label: this.$t('QuotationType'),
                            name: "QuotationType",
                            value: "",
                            disabled: true,
                            placeholder: this.$t('Enter Title Name'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('QuotationOwner'),
                            name: "QuotationOwner",
                            value: "",
                            placeholder: this.$t('Enter Title Name'),
                            config: { options: [] },
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Issue Date (M/D/YYYY)'),
                            name: "IssueDate",
                            value: '',
                            config: { format: "M/D/YYYY" },
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Due Date (M/D/YYYY)'),
                            name: "DueDate",
                            value: '',
                            config: { format: "M/D/YYYY" },
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SlotField",
                            label: this.$t('Template'),
                            name: "TemplateId",
                            value: "",
                            placeholder: this.$t('Enter Title Name'),
                            config: { options: [] },
                            validationRules: { "required": true, max: 100 },
                        },
                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SlotField",
                            name: "BillingItems",
                            value: "",
                            validationRules: { "required": false, max: 100 },
                        },
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                },
            ],
            BillingItems: [],
            Adjustments: [],
            TemplateData: [],
            TotalProfitAmount: 0,
            TotalLinePrice: 0,
            AmountAfterDiscount: '',
            FlatDiscount: '',
            AdvanceRecieved: '',
            NetPayableAmount: '',
            IsPreviewTemplate: false,
            content: '',
            // hdnTotalDiscount:20,
            // hdnTotalTax:20,
            // Counter:20,
            hdnTotalDiscount: 0,
            hdnTotalTax: 0,
            Counter: 20,
            clientId: null,
            clientName: null,
            crmName: null,
            description: null,
            discountType: null,
            endDate: null,
            isClientActive: null,
            iso_Code: null,
            leadId: null,
            leadOwnerId: null,
            owner: null,
            projectName: null,
            projectRequestId: null,
            projectRequestTitle: null,
            quotationId: null,
            quotationNumber: null,
            quotationOwner: null,
            quotationType: null,
            quotationTypeCode: null,
            quotationTypeID: null,
            shippingAddress: null,
            startDate: null,
            statusId: null,
            status: null,
            reqfrom: '',
            TotalTaxAndDiscount: 0.00,
            titile:''

        }
    },
    created: function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.Currency = vm.$route.params.currency;
        vm.ProjectId = vm.$route.params.id;
        vm.reqfrom = vm.$route.params.reform;
        vm.quotationTypeCode = vm.$route.params.code;
        vm.clientId = vm.$route.params.clientId;
        vm.titile = vm.$route.params.titile;
        vm.GetQuotationOwners();
        vm.TemplateList();
        vm.Create();
        const savedData = localStorage.getItem("EditQuoteData");
        if (savedData) {
            this.EditQuoteDate = JSON.parse(savedData);
            vm.EditQuote(this.EditQuoteDate);
        }
    },
    methods: {
        DeleteRow: function (type, itemObj, index) {
            var ths = this;
            if (type == 'Billing') {
                ths.AmountAfterDiscount = parseFloat(ths.AmountAfterDiscount) - parseFloat(itemObj.billedAmount);
                ths.NetPayableAmount = parseFloat(ths.AmountAfterDiscount);
                ths.BillingItems.splice(index, 1);
                ths.CalculateAll();
            } else if (type == 'Discounts') {
                ths.NetPayableAmount = parseFloat(ths.NetPayableAmount) + parseFloat(ths.Adjustments[index].adjAmount);
                ths.AmountAfterDiscount = parseFloat(ths.NetPayableAmount);
                ths.Adjustments.splice(index, 1);
                // ths.CalculateAll();
            }
            else if (type == 'Tax') {
                ths.NetPayableAmount = parseFloat(ths.NetPayableAmount) - parseFloat(ths.Adjustments[index].adjAmount);
                ths.AmountAfterDiscount = parseFloat(ths.NetPayableAmount);
                ths.Adjustments.splice(index, 1);
                // ths.CalculateAll();
            }
        },
        AddDisOrTaxRow: function (evt) {
            var ths = this;
            const target = evt.target;
            const textAttribute = target.getAttribute('id');
            var itemNo = ths.Counter + 1;
            var AdjOperator = '1';
            var adjType = '';
            var totalLinePrice = ths.TotalLinePrice;
            var discount = ths.hdnTotalDiscount;
            if (totalLinePrice == '' || parseFloat(totalLinePrice) <= 0) {
                ths.ShowAlert(ths.$t('Amount is less than or equal to Zero.'), "warning", true, ths.$t("Alert"));
                return false;
            }
            else {
                if (discount != '') {
                    if (parseFloat(totalLinePrice) - parseFloat(discount) <= 0) {
                        ths.ShowAlert(ths.$t('DiscountAdj'), "warning", true, ths.$t("Alert"));
                        return false;
                    }
                }
            }
            if (textAttribute == "ancAddDiscount") {
                adjType = 'Discounts';
                AdjOperator = '0';
            }
            if (textAttribute == "ancAddTax") {
                adjType = 'Tax';
                AdjOperator = '1';
            }
            if (adjType == '' || adjType == undefined)
                return;
            var obj = {
                adjustmentID: 0,
                adjName: "",
                adjOperator: AdjOperator,
                adjType: adjType,
                adjAmount: 0,
                adjPercentage: 18,
                createdBy: 0,
                modifiedBy: 0,
                createdAt: "",
                modifiedAt: "",
                statusId: 0
            };
            ths.Adjustments.push(obj);
        },
        linkPreviewtemplate: function () {
            var ths = this;
            ths.isLoading = true;
            var url = `TemplateId=${ths.SetTemplateId}`
            DataService.Previewtemplate(url).then((response) => {
                if (response.data.content != '') {
                    ths.IsPreviewTemplate = true;
                    ths.content = response.data.content;
                    ths.isLoading = false;
                } else {
                    ths.ShowAlert(ths.$t('Please Select Template.'), "warning", true, ths.$t("Alert"));
                    ths.isLoading = false;
                }
            })

        },
        GenerateNumber: function (evt) {
            const target = evt.target;
            const textAttribute = target.getAttribute('text');
            if (textAttribute == 'gn') {
