        CalculatePricePerRow(item, index, type) {
            var ths = this;
            ths.NetPayableAmount;
            const cost = item.costing;
            const bill = item.billing;
            const quantity = item.quantity;
            if (cost === '') {
                if (bill !== '' && quantity !== '') {
                    rowAmount = parseFloat(b) * parseFloat(q);
                    rowProfitLoss = 0.00;
                } else {
                    rowAmount = 0.00;
                    rowProfitLoss = 0.00;
                }
            } else if (cost !== '' && bill !== '' && bill != undefined && quantity !== '' && quantity != null) {
                item.billedAmount = parseFloat(bill) * parseFloat(quantity);
                item.profit = (parseFloat(bill) - parseFloat(cost)) * parseFloat(quantity);
                ths.CalculateAll(type);
                ths.CalculateTotalDiscountPrice(item, type);
                ths.CalculateTotalTax(item, type);
            } else {
                item.billedAmount = 0.00;
