        CalculateAll: function (type) {
            var ths = this;
            ths.CalculateTotalLineItemPrice(type);
            ths.AmountAfterTaxDis(type);
            ths.ExtraDiscountAndAdvance(type);
        },
        CalculateTotalLineItemPrice: function () {
            var ths = this;
            var totalLineItemAmount = 0;
            var totalLineItemProfitLoss = 0;
            ths.BillingItems.forEach((item) => {
                if (item.billedAmount !== '') {
                    totalLineItemAmount = parseFloat(totalLineItemAmount) + parseFloat(item.billedAmount);
                }
                if (item.profit !== '') {
                    totalLineItemProfitLoss = parseFloat(totalLineItemProfitLoss) + parseFloat(item.profit);
                }
            })
            ths.TotalLinePrice = totalLineItemAmount;
            ths.TotalProfitAmount = totalLineItemProfitLoss;
        },
        DiscountChange: function (data, index) {
            var ths = this;
            ths.CalculateTotalDiscountPrice(data);
            //ths.CalculateTotalTax(data);
            ths.AmountAfterTaxDis();
            ths.ExtraDiscountAndAdvance();
        },
        TaxChange: function (data, index) {
            var ths = this;
            ths.CalculateTotalTax(data);
            ths.AmountAfterTaxDis();
            ths.ExtraDiscountAndAdvance();
        },
        ExtraDiscountAndAdvance: function () {
            var ths = this;
            var totalAmountAftreTaxAndDis = parseFloat(ths.AmountAfterDiscount);
            var flatDiscount = ths.FlatDiscount;
            if (flatDiscount == '' || ((parseFloat(totalAmountAftreTaxAndDis) - parseFloat(flatDiscount)) < 0)) {
                ths.FlatDiscount = 0.00;
                ths.NetPayableAmount = totalAmountAftreTaxAndDis;
            }
            else {
                amountAfterFlatDiscount = parseFloat(totalAmountAftreTaxAndDis) - parseFloat(ths.FlatDiscount);
                ths.NetPayableAmount = totalAmountAftreTaxAndDis;
            }

            var advanceRecieved = ths.AdvanceRecieved;
            if (advanceRecieved == '') {
                ths.AdvanceRecieved = 0.00;
            } else {
                var netAmount = Globalize.parseFloat(amountAfterFlatDiscount) - Globalize.parseFloat(advanceRecieved);
                ths.NetPayableAmount = netAmount;
            }
            if (isNaN(parseFloat(ths.NetPayableAmount))) {
                ths.NetPayableAmount = 0.00;
            }
        },
        CalculateTotalDiscountPrice: function (data) {
            var ths = this;
            var rowDis = 0.00;
            var copyAmount = 0.00;
            var totalDiscount = 0.00;
            var checkedInput = document.querySelector('input[name="DiscountType"]:checked').value == 0 ? true : false;
            var totalLinePrice = ths.TotalLinePrice;
            if (totalLinePrice == '') {
                copyAmount = 0.00;
            } else {
                copyAmount = parseFloat(totalLinePrice);
            }
            if (totalLinePrice == '' || parseFloat(totalLinePrice) <= 0) {
                data.adjAmount = 0.00;
            } else {
                var disPercentage = data.adjPercentage;
                if ($.trim(disPercentage) == '') {
                    rowDis = 0.00;
                    data.adjAmount = 0.00;
                } else {
                    rowDis = (parseFloat(disPercentage) * parseFloat(copyAmount)) / 100;
                    if ((parseFloat(rowDis) + parseFloat(totalDiscount)) <= parseFloat(totalLinePrice)) {
                        data.adjAmount = rowDis;
                        totalDiscount = parseFloat(totalDiscount) + parseFloat(rowDis);
                        if (checkedInput == true) {
                            copyAmount = parseFloat(copyAmount) - parseFloat(rowDis);
                        }
                    }
                    else {
                        data.adjAmount = 0.00;
                    }
                }
            }
            ths.hdnTotalTax = parseFloat(0);
            ths.hdnTotalDiscount = totalDiscount;

        },
        CalculateTotalTax: function (data) {
            var ths = this;
            var totalTax = 0.00;
            var rowTax = 0.00;
            var amountLeftAfterDiscount = parseFloat(ths.TotalLinePrice) - parseFloat(ths.hdnTotalDiscount);
            if (amountLeftAfterDiscount > 0) {
                var per = data.adjPercentage;
                if ($.trim(per) == '') {
                    data.adjAmount = 0.00;
                }
                else {
                    rowTax = (parseFloat(per) * parseFloat(amountLeftAfterDiscount)) / 100;
                    data.adjAmount = rowTax;
                    totalTax = parseFloat(totalTax) + parseFloat(rowTax);
                }
            }
            else {
                data.adjAmount = 0.00;
            }
            ths.hdnTotalTax = totalTax;
        },
        AmountAfterTaxDis: function (type) {
            var ths = this;
            var amountAfterTaxDiscount = 0.00;
            var totalLinePrice = ths.TotalLinePrice;
            var netLineamount = ths.NetPayableAmount
            var totalTax = ths.hdnTotalTax;
            var totalDis = parseFloat(ths.hdnTotalDiscount);
            var counttaxanddis = 0.00;
            if (totalDis != 0) {
                counttaxanddis = totalDis;
                totalTax = 0;
            }
            else { counttaxanddis = totalTax; }
            if (type == null || type == undefined) {
                totalLinePrice = netLineamount > 0 ? ths.NetPayableAmount : ths.TotalLinePrice;
                ths.TotalTaxAndDiscount += parseFloat(counttaxanddis);
            } else {
                ths.TotalTaxAndDiscount += parseFloat(counttaxanddis);
                totalLinePrice += ths.TotalTaxAndDiscount;
            }

            if (totalLinePrice == '') {
                ths.TotalLinePrice = 0.00;
                ths.hdnTotalDiscount = 0.00;
                ths.hdnTotalTax = 0.00;
            }
            else {
                if (totalDis == '' || totalDis == 0) {
                    if (totalTax == '' || totalTax == 0) {
                        amountAfterTaxDiscount = totalLinePrice;
                    }
                    else {
                        amountAfterTaxDiscount = parseFloat(totalLinePrice) + parseFloat(totalTax);
                    }
                }
                else {
                    if (totalTax != '' && totalTax != 0) {
                        amountAfterTaxDiscount = (parseFloat(totalLinePrice) - parseFloat(totalDis)) + parseFloat(totalTax);
                    }
                    else {
                        amountAfterTaxDiscount = parseFloat(totalLinePrice) - parseFloat(totalDis);
                    }
                }
            }
            ths.hdnTotalTax = parseFloat(0);
            ths.hdnTotalDiscount = parseFloat(0);
            ths.AmountAfterDiscount = amountAfterTaxDiscount;
            if (isNaN(parseFloat(ths.AmountAfterDiscount))) {
                ths.AmountAfterDiscount = 0.00;
            }
        },
